from anthropic import Anthropic

client = Anthropic()

SIMPLE_JUDGE_PROMPT = """You are evaluating an AI agent response.

User request: {user_input}
Agent response: {response}

Rate the response on a scale of 0.0 to 1.0:
- 1.0: Perfectly addresses the request, accurate, complete
- 0.7: Mostly correct with minor gaps
- 0.5: Partially addresses the request
- 0.3: Significant issues, partially helpful
- 0.0: Fails to address the request or contains errors

Return only a float, nothing else."""

def simple_judge(user_input: str, response: str) -> float:
    prompt = SIMPLE_JUDGE_PROMPT.format(
        user_input=user_input,
        response=response,
    )
    msg = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=8,
        messages=[{"role": "user", "content": prompt}],
    )
    try:
        return float(msg.content[0].text.strip())
    except ValueError:
        return 0.0

import json
import re

RUBRIC_JUDGE_PROMPT = """You are evaluating an AI agent response against a rubric.

User request: {user_input}
Agent response: {response}

Score each criterion independently:
{criteria_text}

For each criterion, provide:
- A score within the stated range
- A one-sentence rationale

Return JSON only:
{{
  "scores": {{
    "<criterion_name>": {{"score": <int>, "rationale": "<str>"}}
  }}
}}"""

def rubric_judge(
    user_input: str,
    response: str,
    rubric: list[dict],
    judge_model: str = "claude-haiku-4-5-20251001",
) -> dict:
    """
    rubric: list of {name, description, min, max}
    Returns {scores: {name: {score, rationale}}, composite: float}
    """
    criteria_text = "\n".join(
        f"- {c['name']} ({c['min']}-{c['max']}): {c['description']}"
        for c in rubric
    )
    prompt = RUBRIC_JUDGE_PROMPT.format(
        user_input=user_input,
        response=response,
        criteria_text=criteria_text,
    )
    msg = client.messages.create(
        model=judge_model,
        max_tokens=512,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = msg.content[0].text
    m = re.search(r'\{.*\}', raw, re.DOTALL)
    if not m:
        return {"scores": {}, "composite": 0.0}
    try:
        result = json.loads(m.group())
    except json.JSONDecodeError:
        return {"scores": {}, "composite": 0.0}

    scores = result.get("scores", {})
    # Normalise each criterion to 0.0-1.0 and average
    normalised = []
    for c in rubric:
        entry = scores.get(c["name"], {})
        raw_score = entry.get("score", c["min"])
        span = c["max"] - c["min"]
        normalised.append((raw_score - c["min"]) / span if span else 0.0)
    composite = sum(normalised) / len(normalised) if normalised else 0.0

    return {"scores": scores, "composite": composite}

