import re
from typing import TypedDict

class JudgeOutput(TypedDict):
    score: float
    rationale: str

def parse_judge_output(raw: str, fallback: float = 0.0) -> JudgeOutput:
    """
    Parse judge output robustly.
    Tries JSON first, then extracts the first float found.
    """
    # Try JSON
    try:
        data = json.loads(raw)
        return JudgeOutput(
            score=float(data["score"]),
            rationale=data.get("rationale", ""),
        )
    except (json.JSONDecodeError, KeyError, ValueError):
        pass

    # Extract first float
    m = re.search(r'\b([0-9](?:\.[0-9]+)?)\b', raw)
    if m:
        return JudgeOutput(score=float(m.group(1)), rationale=raw)
    return JudgeOutput(score=fallback, rationale=raw)

from enum import StrEnum

class JudgePreset(StrEnum):
    FAST    = "claude-haiku-4-5-20251001"   # high-volume, simple rubrics
    PRECISE = "claude-opus-4-8"             # complex rubrics, safety gates

def select_judge_model(
    rubric_criteria_count: int,
    is_safety_critical: bool,
    daily_call_volume: int,
) -> str:
    if is_safety_critical:
        return JudgePreset.PRECISE
    if rubric_criteria_count >= 4:
        return JudgePreset.PRECISE
    if daily_call_volume > 10_000:
        return JudgePreset.FAST
    return JudgePreset.FAST
